const { ethers } = require('ethers');
const Web3 = require('web3');

class EthereumService {
  constructor() {
    this.provider = null;
    this.wallet = null;
    this.contract = null;
  }

  initialize(providerUrl, privateKey) {
    this.provider = new ethers.providers.JsonRpcProvider(providerUrl);
    this.wallet = new ethers.Wallet(privateKey, this.provider);
    return this.wallet;
  }

  async sendEth(toAddress, amount) {
    try {
      const tx = await this.wallet.sendTransaction({
        to: toAddress,
        value: ethers.utils.parseEther(amount.toString())
      });
      return await tx.wait();
    } catch (error) {
      throw new Error(`Failed to send ETH: ${error.message}`);
    }
  }

  async sendToken(tokenAddress, toAddress, amount) {
    try {
      const tokenABI = [
        "function transfer(address to, uint256 amount) returns (bool)"
      ];
      const tokenContract = new ethers.Contract(tokenAddress, tokenABI, this.wallet);
      const tx = await tokenContract.transfer(toAddress, ethers.utils.parseEther(amount.toString()));
      return await tx.wait();
    } catch (error) {
      throw new Error(`Failed to send token: ${error.message}`);
    }
  }

  async callContractMethod(contractAddress, abi, methodName, args = [], value = 0) {
    try {
      const contract = new ethers.Contract(contractAddress, abi, this.wallet);
      const method = contract[methodName];
      if (!method) {
        throw new Error(`Method ${methodName} not found in contract`);
      }
      const tx = await method(...args, { value: ethers.utils.parseEther(value.toString()) });
      return await tx.wait();
    } catch (error) {
      throw new Error(`Failed to call contract method: ${error.message}`);
    }
  }

  async readContractData(contractAddress, abi, methodName, args = []) {
    try {
      const contract = new ethers.Contract(contractAddress, abi, this.provider);
      const method = contract[methodName];
      if (!method) {
        throw new Error(`Method ${methodName} not found in contract`);
      }
      return await method(...args);
    } catch (error) {
      throw new Error(`Failed to read contract data: ${error.message}`);
    }
  }

  async getBalance(address) {
    try {
      return await this.provider.getBalance(address);
    } catch (error) {
      throw new Error(`Failed to get balance: ${error.message}`);
    }
  }

  async getGasPrice() {
    try {
      return await this.provider.getGasPrice();
    } catch (error) {
      throw new Error(`Failed to get gas price: ${error.message}`);
    }
  }

  async getTransactionCount(address) {
    try {
      return await this.provider.getTransactionCount(address);
    } catch (error) {
      throw new Error(`Failed to get transaction count: ${error.message}`);
    }
  }
}

module.exports = EthereumService;